INSERT INTO rewards (id,name_en,name_fr,type_en,type_fr,category,rarity,version,favor_cost,description_en,description_fr,image_url,image_credit,mission_name_en,mission_name_fr,has_loadout,gives,not_released) VALUES
  ('reward_dm_item_001','Ana Arms Endro; Ana Legs Endro; Ana Core Endro; Ana Helmet Endro','Ana Arms Endro; Ana Legs Endro; Ana Core Endro; Ana Helmet Endro','Armor','Armor','utilities','epic','4.6',NULL,'Hello, know many humans want saldynium for regen problem. Credits good, yes, but Wikelo can use that, kopion horn, and other things to make special armor. Once done, you be very tough. Very scary. You see items needed. Bring to and I make for you. Bye.','Hello, know many humans want saldynium for regen problem. Credits good, yes, but Wikelo can use that, kopion horn, and other things to make special armor. Once done, you be very tough. Very scary. You see items needed. Bring to and I make for you. Bye.','/images/armour_endro.jpg',NULL,'Armor with horn and string','Armor with horn and string',0,1,0),
  ('reward_dm_item_002','Parallax','Parallax','Weapon','Weapon','weapons','epic','4.6',NULL,'Hello. Can make fun change to gun if you want. Use kopion skin for pattern and little skull dangle. Very effective. Shoot much better. All you need is bring me parts to and will make. Bye.','Hello. Can make fun change to gun if you want. Use kopion skin for pattern and little skull dangle. Very effective. Shoot much better. All you need is bring me parts to and will make. Bye.','/images/gun_kopion_military.jpg',NULL,'Fun Kopion Skull Gun','Fun Kopion Skull Gun',0,1,0),
  ('reward_dm_item_003','Parallax','Parallax','Weapon','Weapon','weapons','uncommon','4.6',NULL,'Hello. Can make fun change to gun if you want. If you no like saying it not baby skull, have other choice. Use kopion skin for pattern but use tooth instead dangle. Still effective and shoot better. Bring parts to and will make. Bye.','Hello. Can make fun change to gun if you want. If you no like saying it not baby skull, have other choice. Use kopion skin for pattern but use tooth instead dangle. Still effective and shoot better. Bring parts to and will make. Bye.','/images/gun_kopion_fun.jpg',NULL,'Fun Kopion Tooth Gun','Fun Kopion Tooth Gun',0,1,0),
  ('reward_dm_item_004','Parallax','Parallax','Weapon','Weapon','weapons','epic','4.6',NULL,'Hello. Can do version of gun if you kopion soldier. Make material like soldier camouflage but with dead skull on front. Gun shoot better too. If want, bring part to and will make.','Hello. Can do version of gun if you kopion soldier. Make material like soldier camouflage but with dead skull on front. Gun shoot better too. If want, bring part to and will make.','/images/gun_kopion_military.jpg',NULL,'Fun Military Skull Gun','Fun Military Skull Gun',0,1,0),
  ('reward_dm_item_005','Parallax','Parallax','Weapon','Weapon','weapons','uncommon','4.6',NULL,'Wikelo here with another way to play with type of gun. Make look like more of your soldier gun, but with kopion tooth dangle. Very nasty indeed. If want, bring part to and will make. Bye.','Wikelo here with another way to play with type of gun. Make look like more of your soldier gun, but with kopion tooth dangle. Very nasty indeed. If want, bring part to and will make. Bye.','/images/gun_military_fun.jpg',NULL,'Fun Military Tooth Gun','Fun Military Tooth Gun',0,1,0),
  ('reward_dm_item_006','DCP Armor Helmet Jungle Camo; DCP Armor Core Jungle Camo; DCP Armor Arms Jungle Camo; DCP Armor Legs Jungle Camo','DCP Armor Helmet Jungle Camo; DCP Armor Core Jungle Camo; DCP Armor Arms Jungle Camo; DCP Armor Legs Jungle Camo','Armor','Armor','utilities','uncommon','4.6',NULL,'Hello. You walk in woods but not want people to know? Wikelo have armor for you. If you bring to , you can get. Interest?','Hello. You walk in woods but not want people to know? Wikelo have armor for you. If you bring to , you can get. Interest?','/images/armour_woodland.jpg',NULL,'Want armor look like tree?','Want armor look like tree?',0,1,0),
  ('reward_dm_item_007','DCP Armor Helmet Hunter Camo; DCP Armor Core Hunter Camo; DCP Armor Arms Hunter Camo; DCP Armor Legs Hunter Camo','DCP Armor Helmet Hunter Camo; DCP Armor Core Hunter Camo; DCP Armor Arms Hunter Camo; DCP Armor Legs Hunter Camo','Armor','Armor','utilities','uncommon','4.6',NULL,'You in hot desert doing things. Need to be sneaky. Don''t want seen. Understand. Wikelo give you armor that make you sneaky in sand. Bring things to and I will make. Easy. Bye.','You in hot desert doing things. Need to be sneaky. Don''t want seen. Understand. Wikelo give you armor that make you sneaky in sand. Bring things to and I will make. Easy. Bye.','/images/armour_sandy.jpg',NULL,'Look at desert but don''t see you','Look at desert but don''t see you',0,1,0),
  ('reward_dm_item_008','DCP Armor Helmet Cobalt Camo; DCP Armor Core Cobalt Camo; DCP Armor Arms Cobalt Camo; DCP Armor Legs Cobalt Camo','DCP Armor Helmet Cobalt Camo; DCP Armor Core Cobalt Camo; DCP Armor Arms Cobalt Camo; DCP Armor Legs Cobalt Camo','Armor','Armor','utilities','uncommon','4.6',NULL,'Know you humans like your navy. Wikelo understand. Very big ships. Powerful too. Wikelo can give armor set that look like navy color. Very easy to make. See what Wikelo need, get and bring to and it will be yours. Wikelo','Know you humans like your navy. Wikelo understand. Very big ships. Powerful too. Wikelo can give armor set that look like navy color. Very easy to make. See what Wikelo need, get and bring to and it will be yours. Wikelo','/images/armour_navy.jpg',NULL,'Make space navy armor','Make space navy armor',0,1,0),
  ('reward_dm_item_009','Quartz','Quartz','Weapon','Weapon','weapons','uncommon','4.6',NULL,'Wikelo hearing about new energy weapon by VOLT souli. If you want, Wikelo can make gun look better. It found in storm, it shoot storm, but Wikelo make it better for people who like human navy. Bring things to and Wikelo will do. Bye.','Wikelo hearing about new energy weapon by VOLT souli. If you want, Wikelo can make gun look better. It found in storm, it shoot storm, but Wikelo make it better for people who like human navy. Bring things to and Wikelo will do. Bye.','/images/gun_zappy_navy.jpg',NULL,'Volt gun more Navy-like','Volt gun more Navy-like',0,1,0),
  ('reward_dm_item_010','Quartz','Quartz','Weapon','Weapon','weapons','uncommon','4.6',NULL,'Wikelo hearing about new type of energy weapon by VOLT souli. Hit very hard. If you want, Wikelo can make gun look even better. It found in storm, it shoot storm, but Wikelo make it look woodier. Drop in forest? It gone. Bring things to and Wikelo will do. Bye.','Wikelo hearing about new type of energy weapon by VOLT souli. Hit very hard. If you want, Wikelo can make gun look even better. It found in storm, it shoot storm, but Wikelo make it look woodier. Drop in forest? It gone. Bring things to and Wikelo will do. Bye.','/images/gun_zappy_woodland.jpg',NULL,'Zappy gun more woodlike','Zappy gun more woodlike',0,1,0),
  ('reward_dm_item_011','Quartz','Quartz','Weapon','Weapon','weapons','uncommon','4.6',NULL,'Wikelo can make new VOLT gun look like sand mound. Very sneaky in desert. Bring things to and Wikelo will do. Bye.','Wikelo can make new VOLT gun look like sand mound. Very sneaky in desert. Bring things to and Wikelo will do. Bye.','/images/gun_zappy_sandy.jpg',NULL,'Make gun sandy','Make gun sandy',0,1,0),
  ('reward_dm_item_012','Bokto Core; Bokto Arms; Bokto Legs; Bokto Helmet','Bokto Core; Bokto Arms; Bokto Legs; Bokto Helmet','Armor','Armor','utilities','epic','4.6',NULL,'Wikelo had exciting idea during brief work rest. Was thinking about the little glow worms in Pyro and saw armor get changed to look like. If you get me parts, bring to and will make for you then you can glow too. Bye.','Wikelo had exciting idea during brief work rest. Was thinking about the little glow worms in Pyro and saw armor get changed to look like. If you get me parts, bring to and will make for you then you can glow too. Bye.','/images/armour_endro_glow.jpg',NULL,'Make glowy armor','Make glowy armor',0,1,0),
  ('reward_dm_item_013','Prism','Prism','Weapon','Weapon','weapons','epic','4.6',NULL,'You feel like gun not angry enough? VOLT shotgun very powerful, very dangerous, but not scary? Bring to me. Can make very scary and angry. They respect you then. Bring to and we make. Bye.','You feel like gun not angry enough? VOLT shotgun very powerful, very dangerous, but not scary? Bring to me. Can make very scary and angry. They respect you then. Bring to and we make. Bye.','/images/gun_volt_shot.jpg',NULL,'Make VOLT shotgun angrier','Make VOLT shotgun angrier',0,1,0),
  ('reward_dm_item_014','Novikov','Novikov','Armor','Armor','utilities','rare','4.6',NULL,'Maybe you like walking on planet that very hot. Or very cold. Or many rocks. Wikelo can make suit called Novikov from Human souli Caldera work better for you. Bring things if you want, then I make. Bye.','Maybe you like walking on planet that very hot. Or very cold. Or many rocks. Wikelo can make suit called Novikov from Human souli Caldera work better for you. Bring things if you want, then I make. Bye.','/images/armour_novikov.jpg',NULL,'Walk in danger. Look good.','Walk in danger. Look good.',0,1,0),
  ('reward_dm_item_015','Xanthule Ascension Suit; Xanthule Ascension Helmet','Xanthule Ascension Suit; Xanthule Ascension Helmet','Armor','Armor','utilities','rare','4.6',NULL,'Wikelo like Syang souli very much. Make very line-y flight suits that very useful. Can even make suits a little prettier if you want. Bring things, I do.','Wikelo like Syang souli very much. Make very line-y flight suits that very useful. Can even make suits a little prettier if you want. Bring things, I do.','/images/armour_alien.jpg',NULL,'Xi''an Xanthule Suit made better','Xi''an Xanthule Suit made better',0,1,0),
  ('reward_dm_item_016','Venture Core Ascension; Venture Arms Ascension; Venture Legs Ascension; Venture Helmet Ascension','Venture Core Ascension; Venture Arms Ascension; Venture Legs Ascension; Venture Helmet Ascension','Armor','Armor','utilities','rare','4.6',NULL,'You like adventure, right? This armor good for it. Let you go dangerous places, but not too heavy. Stay light. Wikelo found these and will trade if you want. You win, Wikelo win. Bye.','You like adventure, right? This armor good for it. Let you go dangerous places, but not too heavy. Stay light. Wikelo found these and will trade if you want. You win, Wikelo win. Bye.','/images/armour_adventure.jpg',NULL,'Adventure a A-Venture','Adventure a A-Venture',0,1,0),
  ('reward_dm_item_017','Karna','Karna','Weapon','Weapon','weapons','rare','4.6',NULL,'Wikelo friend had to trade ship they found for credits. Wikelo surprised to find many crate of Karna guns inside. Friend must not have wanted. Anyway, Wikelo figure out how to make prettier. If you want, bring stuff. Bye.','Wikelo friend had to trade ship they found for credits. Wikelo surprised to find many crate of Karna guns inside. Friend must not have wanted. Anyway, Wikelo figure out how to make prettier. If you want, bring stuff. Bye.','/images/gun_karna.jpg',NULL,'Prettify Karna Gun','Prettify Karna Gun',0,1,0),
  ('reward_dm_item_018','S71','S71','Weapon','Weapon','weapons','rare','4.6',NULL,'Universe is dangerous in human space. Good to have a good weapon to handle bad situation. Wikelo don''t have many weapon, but can make useful ones more useful. If you want, bring stuff and I will do.','Universe is dangerous in human space. Good to have a good weapon to handle bad situation. Wikelo don''t have many weapon, but can make useful ones more useful. If you want, bring stuff and I will do.','/images/gun_s71.jpg',NULL,'Built on S71 rifle','Built on S71 rifle',0,1,0),
  ('reward_dm_item_019','Coda','Coda','Weapon','Weapon','weapons','rare','4.6',NULL,'Wikelo found crate of Coda pistols. Very strange reason, but will tell later if you want to hear. Anyway, after study have figured out nice way to make gun look better. Have a look, see if interested. Bye.','Wikelo found crate of Coda pistols. Very strange reason, but will tell later if you want to hear. Anyway, after study have figured out nice way to make gun look better. Have a look, see if interested. Bye.','/images/gun_coda.jpg',NULL,'Fix up Coda gun','Fix up Coda gun',0,1,0),
  ('reward_dm_item_020','Zenith','Zenith','Weapon','Weapon','weapons','epic','4.6',NULL,'Want to shoot long away and stay hiding. But it snowing? Wikelo have gun for you. Bring things. I give. Bye.','Want to shoot long away and stay hiding. But it snowing? Wikelo have gun for you. Bring things. I give. Bye.','/images/gun_volt_snipe.jpg',NULL,'Snow Snipe','Snow Snipe',0,1,0),
  ('reward_dm_item_021','Geist Armor Arms Snow Camo; Geist Armor Core Snow Camo; Geist Armor Helmet Snow Camo; Geist Armor Legs Snow Camo; Geist Backpack Snow Camo','Geist Armor Arms Snow Camo; Geist Armor Core Snow Camo; Geist Armor Helmet Snow Camo; Geist Armor Legs Snow Camo; Geist Backpack Snow Camo','Armor','Armor','utilities','epic','4.6',NULL,'You want be hidden. Wikelo understand. Not ask questions why. But what do when you in snow? Wikelo have suit for that. Welcome.','You want be hidden. Wikelo understand. Not ask questions why. But what do when you in snow? Wikelo have suit for that. Welcome.','/images/armour_geist.jpg',NULL,'Hide Snow Suit','Hide Snow Suit',0,1,0),
  ('reward_dm_item_022','Fresnel','Fresnel','Weapon','Weapon','weapons','uncommon','4.6',NULL,'You need useful weapon. Yes, yes, understand. Wikelo make useful weapon more beautiful too. You see things I need. You bring? I do. Bye.','You need useful weapon. Yes, yes, understand. Wikelo make useful weapon more beautiful too. You see things I need. You bring? I do. Bye.','/images/gun_heavy_volt.jpg',NULL,'Heavy VOLT Zapper','Heavy VOLT Zapper',0,1,0),
  ('reward_dm_item_023','Strata Core Heatwave; Strata Arms Heatwave; Strata Legs Heatwave; Strata Helmet Heatwave; Strata Backpack Heatwave','Strata Core Heatwave; Strata Arms Heatwave; Strata Legs Heatwave; Strata Helmet Heatwave; Strata Backpack Heatwave','Armor','Armor','utilities','epic','4.6',NULL,'If you have armor, Wikelo can make it look warm. Good look for useful armor. Bring me things and will do.','If you have armor, Wikelo can make it look warm. Good look for useful armor. Bring me things and will do.','/images/armour_lava.jpg',NULL,'Do Lava Suit','Do Lava Suit',0,1,0),
  ('reward_dm_item_024','Corbel Helmet Crush; Corbel Core Crush; Corbel Arms Crush; Corbel Legs Crush; Novikov Backpack Crush','Corbel Helmet Crush; Corbel Core Crush; Corbel Arms Crush; Corbel Legs Crush; Novikov Backpack Crush','Armor','Armor','utilities','epic','4.6',NULL,'You need utility suit. Good for work. If you like, Wikelo can make shinier. Look real good. See what Wikelo need and bring.','You need utility suit. Good for work. If you like, Wikelo can make shinier. Look real good. See what Wikelo need and bring.','/images/armour_shiny.jpg',NULL,'Shiny Builder Suit','Shiny Builder Suit',0,1,0),
  ('reward_dm_item_025','XDL','XDL','Armor','Armor','utilities','uncommon','4.6',NULL,'Wikelo has best eyes for seeing far away. I give to you if you give me','Wikelo has best eyes for seeing far away. I give to you if you give me','/images/gear_mono.jpg',NULL,'Want Better Eyes?','Want Better Eyes?',0,1,0),
  ('reward_dm_item_026','Fresnel','Fresnel','Weapon','Weapon','weapons','epic','4.6',NULL,'This gun has picture of amazing creature on side. Use it and it make you big and strong like Yormandi. Spit lightning. Bring my items and then you get it. Bye.','This gun has picture of amazing creature on side. Use it and it make you big and strong like Yormandi. Spit lightning. Bring my items and then you get it. Bye.','/images/gun_yormandi.jpg',NULL,'Yormandi Gun','Yormandi Gun',0,1,0),
  ('reward_dm_item_027','F55','F55','Weapon','Weapon','weapons','uncommon','4.6',NULL,'Sometimes you shoot people, but if you are last thing they see before dead gun should look amazing, right? Wikelo will make your gun look much better. Bring me items I need and then I give you the gun. Bye.','Sometimes you shoot people, but if you are last thing they see before dead gun should look amazing, right? Wikelo will make your gun look much better. Bring me items I need and then I give you the gun. Bye.','/images/gun_f55.jpg',NULL,'F55 Look Better','F55 Look Better',0,1,0),
  ('reward_dm_item_028','Palatino Helmet Mark I; Palatino Arms Mark I; Palatino Legs Mark I; Palatino Core Mark I; Palatino Backpack Mark I','Palatino Helmet Mark I; Palatino Arms Mark I; Palatino Legs Mark I; Palatino Core Mark I; Palatino Backpack Mark I','Armor','Armor','utilities','epic','4.6',NULL,'Bring me armor and other things and I give you special test armor. First version. Very special. Bring and I give. Bye.','Bring me armor and other things and I give you special test armor. First version. Very special. Bring and I give. Bye.','/images/armour_test.jpg',NULL,'Test Armor','Test Armor',0,1,0),
  ('reward_dm_item_029','Testudo Helmet Clanguard; Testudo Arms Clanguard; Testudo Core Clanguard; Testudo Legs Clanguard; Testudo Backpack Clanguard','Testudo Helmet Clanguard; Testudo Arms Clanguard; Testudo Core Clanguard; Testudo Legs Clanguard; Testudo Backpack Clanguard','Armor','Armor','utilities','epic','4.6',NULL,'Vanduul have strange ways. I never talk to them, old souli used to, but not Wikelo. Anyway, though not friendly, they make interesting thing. If you like, Wikelo can make you look more like. Bring things. Will do. Bye.','Vanduul have strange ways. I never talk to them, old souli used to, but not Wikelo. Anyway, though not friendly, they make interesting thing. If you like, Wikelo can make you look more like. Bring things. Will do. Bye.','/images/armour_vanduul.jpg',NULL,'Armor with Vanduul','Armor with Vanduul',0,1,0),
  ('reward_dm_item_030','Boomtube','Boomtube','Armor','Armor','utilities','epic','4.6',NULL,'Wikelo find very strange but functional weapon while wandering through your systems. It very simple but very effective. If you bring me things, I show you what I do to it. Very fun.','Wikelo find very strange but functional weapon while wandering through your systems. It very simple but very effective. If you bring me things, I show you what I do to it. Very fun.','/images/gun_boomtube.jpg',NULL,'Curious Weapon','Curious Weapon',0,1,0),
  ('reward_dm_item_031','Tripledown','Tripledown','Weapon','Weapon','weapons','epic','4.6',NULL,'You need a good weapon, yes? Have one for you. Small but powerful. Like an extra spicy balalu pepper. Wikelo make this pistol look extra spicy too. You bring things I need and I do a trade. Bye.','You need a good weapon, yes? Have one for you. Small but powerful. Like an extra spicy balalu pepper. Wikelo make this pistol look extra spicy too. You bring things I need and I do a trade. Bye.','/images/gun_shot.jpg',NULL,'Hot Shot','Hot Shot',0,1,0),
  ('reward_dm_item_033','Very Hungry','Very Hungry','Gear','Gear','utilities','epic','4.6',NULL,'You humans keep Wikelo very busy. Work more than when I at old souli. But Wikelo very hungry now and can''t get food. Please help. Bring food and drink to Wikelo Emporium at . Very appreciate your help. Will give thing in return. Bye.','You humans keep Wikelo very busy. Work more than when I at old souli. But Wikelo very hungry now and can''t get food. Please help. Bring food and drink to Wikelo Emporium at . Very appreciate your help. Will give thing in return. Bye.',NULL,NULL,'Very Hungry','Very Hungry',0,1,0),
