  ('reward_dm_ship_038','Kruger L-21 Wolf Wikelo War Special; Antium Helmet Midnight Sun; Antium Core Midnight Sun; Antium Arms Midnight Sun; Antium Legs Midnight Sun; Fresnel "Deepwater" Energy LMG','Kruger L-21 Wolf Wikelo War Special; Antium Helmet Midnight Sun; Antium Core Midnight Sun; Antium Arms Midnight Sun; Antium Legs Midnight Sun; Fresnel "Deepwater" Energy LMG','Ship','Ship','ships','epic','4.6',NULL,'','',NULL,NULL,'Most Special Wolf','Most Special Wolf',1,1,0),
  ('reward_dm_ship_039','Aegis Idris-P Wikelo War Special','Aegis Idris-P Wikelo War Special','Ship','Ship','ships','epic','4.6',NULL,'','',NULL,NULL,'Special Idris For Killing','Special Idris For Killing',1,1,0),
  ('reward_dm_item_032','Wikelo Arrive to System','Wikelo Arrive to System','Intro','Intro','utilities','epic','4.6',NULL,'Hello, I am Wikelo. Recent addition to your system and very excited to be here. Spent many time here in UEE and happy to spent more. Have place where I make things from other things. Need person to bring me useful things to finish project I work on. You have list. Get, please. I am at . Will give you item for your help. Also, when done, if you want to do more. Have many things can make in my humble shop. Come, look at pretty poster and then decide what you want me to make. Bye.','Hello, I am Wikelo. Recent addition to your system and very excited to be here. Spent many time here in UEE and happy to spent more. Have place where I make things from other things. Need person to bring me useful things to finish project I work on. You have list. Get, please. I am at . Will give you item for your help. Also, when done, if you want to do more. Have many things can make in my humble shop. Come, look at pretty poster and then decide what you want me to make. Bye.',NULL,NULL,'Wikelo Arrive to System','Wikelo Arrive to System',0,1,0),
  ('reward_dm_exchange_trade_worm_parts_for_favors','Wikelo Favor','Wikelo Favor','Currency','Currency','utilities','epic','4.6',NULL,'Have new way to get favors from Wikelo. Hear much about worm things in radiation storms. Made up of many interesting parts that Wikelo find use for. If you bring parts to , will trade for favor. Bye.','Have new way to get favors from Wikelo. Hear much about worm things in radiation storms. Made up of many interesting parts that Wikelo find use for. If you bring parts to , will trade for favor. Bye.',NULL,NULL,'Trade Worm Parts for Favors?','Trade Worm Parts for Favors?',0,1,0),
  ('reward_dm_exchange_trade_merc_scrip_for_favors','Wikelo Favor','Wikelo Favor','Currency','Currency','utilities','epic','4.6',NULL,'Wikelo has another way to get favors if you interested. Your Mercenary souli has scrip metal, used like favors, but made of very interesting metal that Wikelo need for new project. If you bring scrips to , will trade for favor. Bye.','Wikelo has another way to get favors if you interested. Your Mercenary souli has scrip metal, used like favors, but made of very interesting metal that Wikelo need for new project. If you bring scrips to , will trade for favor. Bye.',NULL,NULL,'Trade Merc Scrip for Favors?','Trade Merc Scrip for Favors?',0,1,0),
  ('reward_dm_exchange_trade_council_scrip_for_favors','Wikelo Favor','Wikelo Favor','Currency','Currency','utilities','epic','4.6',NULL,'If you want other way to get favors from Wikelo, have thing for you. Wikelo have need for scrip given out by Council group. Wikelo not part of thief souli, but has business from time to time. If you bring scrips to , will trade for favor. Bye.','If you want other way to get favors from Wikelo, have thing for you. Wikelo have need for scrip given out by Council group. Wikelo not part of thief souli, but has business from time to time. If you bring scrips to , will trade for favor. Bye.',NULL,NULL,'Trade Council Scrip for Favors?','Trade Council Scrip for Favors?',0,1,0),
  ('reward_dm_exchange_turn_things_to_favor','Wikelo Favor','Wikelo Favor','Currency','Currency','utilities','epic','4.6',NULL,'Maybe Wikelo not have something you want made (that strange, but okay). Old souli would give out favors, very good way to prove that you do work for me. Collect enough and trade when I have something you want. Bring things to and will trade for favor. Bye.','Maybe Wikelo not have something you want made (that strange, but okay). Old souli would give out favors, very good way to prove that you do work for me. Collect enough and trade when I have something you want. Bring things to and will trade for favor. Bye.',NULL,NULL,'Turn Things to Favor','Turn Things to Favor',0,1,0),
  ('reward_dm_exchange_want_polaris_need_something_special','Polaris Bit','Polaris Bit','Currency','Currency','utilities','epic','4.6',NULL,'Wikelo need large amounts of quantanium and is willing to give you nice Polaris in exchange but also know many humans not have much space, so you trade as you go. Wikelo will you Polaris bits if you want trade quantanium. Work like favors. Help Wikelo remember how much you give. Bring quantanium to and will trade for bits. Bye.','Wikelo need large amounts of quantanium and is willing to give you nice Polaris in exchange but also know many humans not have much space, so you trade as you go. Wikelo will you Polaris bits if you want trade quantanium. Work like favors. Help Wikelo remember how much you give. Bring quantanium to and will trade for bits. Bye.',NULL,NULL,'Want Polaris? Need something special.','Want Polaris? Need something special.',0,1,0)
